import React from "react";

import ProductList from "../components/ProductList/ProductList";


function Home() {

    return (

        <div>

            <section
                className="hero"
            >

                <h1>

                    Welcome To ShopEase

                </h1>

                <p>

                    Discover amazing products at affordable prices.

                </p>

            </section>


            <ProductList />

        </div>

    );

}


export default Home;
